# Category: serverless_security

from flask import Flask, request
from google.cloud import storage
import json

app = Flask(__name__)

# Allow requests from any origin (Access-Control-Allow-Origin - *) for development purposes
@app.after_request
def after_request(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    return response

@app.route('/upload', methods=['POST'])
def upload():
    data = request.get_json()

    # Get the uploaded file from the request body and save it to Cloud Storage
    file = data['file']
    bucket = storage.Client().bucket('my-bucket')
    blob = bucket.blob(f'{data["name"]}.txt')
    blob.upload_from_string(file.read())

    # Return a success response
    return json.dumps({'success': True}), 200, {'Content-Type': 'application/json'}